// Map: assigning a missing key creates an entry
Map<int, String> l = {1: '😎', 2: '🤩'};
l[5] = '😍';                    // l is now {1:'😎', 2:'🤩', 5:'😍'}

// List with mixed types via Object — fine!
List<Object> mixed = [1, 'two', 3.0];   // ✓ no error

// remove() only removes the FIRST occurrence
List<int> nums = [1, 2, 1, 3];
nums.remove(1);                  // [2, 1, 3] — second 1 still there

// insert at index 1 shifts the rest right
List<String> animals = ['🐓', '🐄', '🐖'];
animals.insert(1, '🐒');         // ['🐓', '🐒', '🐄', '🐖']

String snake = 'apples_and_pears';

// Step 1: split on '_'
List<String> words = snake.split('_');   // ['apples', 'and', 'pears']

// Step 2: capitalise each word after the first
String camel = words.first +
    words.skip(1).map((w) =>
        w[0].toUpperCase() + w.substring(1)).join();
// camel == 'applesAndPears'

String s = 'Flutter';
//          F l u t t e r
// index:   0 1 2 3 4 5 6

s.indexOf('t');     // 3 — first match
s.lastIndexOf('t'); // 4 — last match

Map<String, int> scores = {'Dhivyah': 90, 'Álvaro': 85};

scores.remove('Álvaro');     // ✓ removes by key
// scores is now {'Dhivyah': 90}

// scores.delete(...)          ✗ no such method on Map
// scores.remove(0)            ✗ Maps don't use indices
// scores.remove('Álvaro', 85) ✗ remove takes ONLY the key

// In Dart, _ makes a member library-private (file-private if it's its own file).
// Within the SAME file, _password IS accessible from another class:

// user.dart
class User {
  String _password = 'secret';
}
class Admin {
  void leak(User u) => print(u._password);  // ✓ same library
}

// extends for inheritance:
class Player {}
class Goalkeeper extends Player {}

// A class can hold a List of another class:
class Team {
  List<Player> players = [];
}

// lect18.dart  (one library)
class BankAccount {
  String accountNumber;
  double _balance = 0.0;        // library-private
  BankAccount(this.accountNumber);
  double get balance => _balance;  // PUBLIC getter
}

// main.dart  (different library)
import 'lect18.dart';
void main() {
  var a = BankAccount('123');
  a.deposit(50);              // ✓ public method
  print(a.balance);           // ✓ public getter
  // print(a._balance);       ✗ private to lect18.dart
  // a.balance = 100;         ✗ no setter defined
}
